#include <iostream>
class Base {
public:
    virtual void doSomething() const = 0;
    virtual ~Base() = default;
};
class Derived : public Base {
public:
    void doSomething() const override {
        std::cout << "Derived implementation" << std::endl;
    }
};
void useBase(const Base& b) { b.doSomething(); }
int main() {
    Derived d;
    useBase(d);
    return 0;
}
